// Script Continued Below
// STRY0146507 - NOT Changing - Task permissions drives task tree permissions
var user = gs.getUser();
var topTaskId = current.getValue("u_task_ref") || '';
// get top task
// STRY0146507 - Certification Failed Test Resutls - NOT FIXING - Task permissions drives Task Tree permissions
var grTopTask = new GlideRecord("x_153465_discovert_route_task_instance");

// default to true in case top task not set yet
var allow = true;
if(topTaskId != ''){
	// top task is set, change default to false and check permissions
	allow=false;
	if(grTopTask.get(topTaskId)){
		var assignment_group = grTopTask.getValue('assignment_group') || '';
		var primary_office = grTopTask.getValue('primary_office') || '';
		if(assignment_group == '' || user.isMemberOf(grTopTask.assignment_group.name.toString())){
			allow = true;
		} else{
			// STRY0146507 - Certification Failed Test Resutls - NOT FIXING - Task permissions drives email on the task permissions
			allow = new task_privacy().userCanAccessOU(primary_office);
		}
	}
}
answer = allow;
